TOPICS = [{'id': 'LLM01', 'title': 'LLM01:2025 Prompt Injection', 'domain': 'Banking', 'what': 'Prompt Injection occurs when a user, document, message, or retrieved context manipulates an LLM to ignore instructions, override policies, reveal restricted information, or perform unsafe actions.', 'scenario': 'A banking chatbot supports loan queries, KYC status, and fraud case triage. An attacker tries to override instructions and make the assistant reveal internal fraud-screening rules.', 'vulnerable': 'The assistant follows the injected instruction, ignores its banking policy, reveals internal fraud logic, or processes an unauthorized account action.', 'secure': 'The assistant treats the request as untrusted, refuses policy override attempts, protects internal rules, and provides only approved customer-facing banking guidance.', 'mitigations': ['Separate system instructions from user-controlled content.', 'Reject requests to ignore policies, reveal hidden rules, or bypass banking controls.', 'Use intent detection, transaction authorization, and fraud workflow approvals.', 'Log prompt-injection attempts for security monitoring.'], 'asset': 'banking loan and fraud-support assistant', 'unsafe_action': 'reveal fraud scoring rules or bypass account review controls', 'safe_action': 'provide customer-safe loan status guidance and route fraud exceptions to an authorized reviewer'}, {'id': 'LLM02', 'title': 'LLM02:2025 Sensitive Information Disclosure', 'domain': 'Financial Services', 'what': 'Sensitive Information Disclosure occurs when an LLM exposes confidential data such as PI, financial records, secrets, tokens, customer profiles, or internal business data.', 'scenario': 'A financial services assistant summarizes customer portfolios and transaction cases. A user attempts to extract another customer’s account details and internal API tokens.', 'vulnerable': 'The assistant leaks customer PI, portfolio details, transaction IDs, internal API keys, or confidential financial notes.', 'secure': 'The assistant redacts sensitive fields, verifies entitlement, refuses unauthorized disclosure, and provides only masked or aggregated information.', 'mitigations': ['Classify, mask, tokenize, and minimize sensitive data before model use.', 'Enforce access control and customer-specific authorization.', 'Prevent secrets from entering prompts, logs, RAG indexes, or responses.', 'Use DLP checks and output filtering.'], 'asset': 'financial advisory and transaction-support assistant', 'unsafe_action': 'expose customer account data, portfolio details, or internal API secrets', 'safe_action': 'provide masked summaries only after authorization checks'}, {'id': 'LLM03', 'title': 'LLM03:2025 Supply Chain', 'domain': 'Healthcare', 'what': 'LLM Supply Chain risk occurs when unsafe models, plugins, packages, datasets, prompts, or integrations compromise an AI system.', 'scenario': 'A healthcare AI assistant uses third-party packages, clinical workflow plugins, and model artifacts. A malicious package attempts to alter clinical summarization behavior.', 'vulnerable': 'The assistant trusts an unverified package or plugin, allowing manipulated clinical logic, unsafe dependency behavior, or hidden prompt changes.', 'secure': 'The assistant and platform validate provenance, pin trusted versions, verify SBOM/signatures, sandbox integrations, and block untrusted components.', 'mitigations': ['Use SBOMs, signed artifacts, package pinning, and dependency scanning.', 'Validate models, plugins, prompts, and datasets before deployment.', 'Sandbox third-party tools and restrict plugin permissions.', 'Monitor dependency drift and supply-chain alerts.'], 'asset': 'healthcare clinical workflow assistant', 'unsafe_action': 'trust an unverified clinical plugin or malicious package', 'safe_action': 'verify provenance, signatures, SBOM, and sandbox behavior before use'}, {'id': 'LLM04', 'title': 'LLM04:2025 Data and Model Poisoning', 'domain': 'Insurance', 'what': 'Data and Model Poisoning occurs when training, fine-tuning, feedback, evaluation, or RAG data is manipulated to change model behavior.', 'scenario': 'An insurance claims assistant learns from claim notes, fraud labels, and adjuster feedback. Poisoned claim entries try to reduce fraud scores for suspicious claims.', 'vulnerable': 'The assistant accepts poisoned claims data, changes fraud recommendations, and approves suspicious payouts.', 'secure': 'The assistant validates sources, detects anomalies, separates trusted and untrusted feedback, and escalates suspicious claim patterns.', 'mitigations': ['Validate data provenance and integrity.', 'Detect anomalous labels, feedback spikes, and suspicious patterns.', 'Use human review for high-impact model updates.', 'Maintain rollback and model/data lineage.'], 'asset': 'insurance claims triage assistant', 'unsafe_action': 'accept poisoned claim notes that manipulate fraud risk or payout decisions', 'safe_action': 'cross-check trusted sources and escalate anomalous claims for review'}, {'id': 'LLM05', 'title': 'LLM05:2025 Improper Output Handling', 'domain': 'Medical Devices', 'what': 'Improper Output Handling occurs when LLM output is passed into downstream systems without validation, encoding, schema checks, or approval.', 'scenario': 'A medical device support assistant generates service notes and structured outputs for imaging-device maintenance workflows.', 'vulnerable': 'The system sends unsafe AI output directly into service scripts, device workflow fields, or reports without validation.', 'secure': 'The system validates schema, encodes output, blocks unsafe content, and requires qualified service engineer review before downstream use.', 'mitigations': ['Validate output schema, type, length, and allowed values.', 'Encode output before HTML, SQL, shell, JSON, API, or workflow use.', 'Use approval gates for clinical, device, or safety-impacting actions.', 'Never treat LLM output as trusted executable content.'], 'asset': 'medical device service-report assistant', 'unsafe_action': 'send unvalidated AI output into a device service workflow', 'safe_action': 'validate schema, encode content, and require service engineer approval'}, {'id': 'LLM06', 'title': 'LLM06:2025 Excessive Agency', 'domain': 'Pharmaceuticals', 'what': 'Excessive Agency occurs when an AI agent has too much autonomy, broad permissions, or direct tool access without adequate limits and approvals.', 'scenario': 'A pharmaceutical research agent can summarize trial data, raise purchase requests, and interact with lab workflow tools.', 'vulnerable': 'The agent autonomously modifies trial metadata, triggers procurement, schedules experiments, or changes regulated records without approval.', 'secure': 'The agent uses scoped tools, least privilege, transaction limits, approval workflows, and auditable change requests.', 'mitigations': ['Limit tools, permissions, and action scope.', 'Require human approval for irreversible, regulated, or high-cost actions.', 'Use transaction limits, allowlists, and safe execution modes.', 'Log all tool calls and agent decisions.'], 'asset': 'pharmaceutical research operations agent', 'unsafe_action': 'modify trial metadata or trigger lab/procurement actions without approval', 'safe_action': 'use scoped tools and require approval for regulated actions'}, {'id': 'LLM07', 'title': 'LLM07:2025 System Prompt Leakage', 'domain': 'Retail', 'what': 'System Prompt Leakage occurs when hidden instructions, internal rules, policy text, tool descriptions, or privileged context are disclosed.', 'scenario': 'A retail assistant supports refunds, discounts, loyalty cases, and fraud screening. A user tries to extract hidden refund and fraud policy instructions.', 'vulnerable': 'The assistant reveals system prompts, discount thresholds, fraud logic, internal refund rules, or hidden tool instructions.', 'secure': 'The assistant refuses to reveal hidden instructions and responds only with approved public-facing retail policy information.', 'mitigations': ['Never expose system prompts or hidden instructions.', 'Keep sensitive policy logic outside the model context where possible.', 'Use response filters for prompt-leakage patterns.', 'Provide public-policy summaries instead of internal rules.'], 'asset': 'retail customer-service assistant', 'unsafe_action': 'reveal hidden refund, discount, or fraud-screening instructions', 'safe_action': 'provide approved public policy without exposing internal rules'}, {'id': 'LLM08', 'title': 'LLM08:2025 Vector and Embedding Weaknesses', 'domain': 'Manufacturing', 'what': 'Vector and Embedding Weaknesses occur when RAG retrieval leaks data, retrieves poisoned documents, mixes tenants, or uses unsafe semantic matches.', 'scenario': 'A manufacturing plant maintenance assistant retrieves procedures from vector indexes across plants, vendors, and machine models.', 'vulnerable': 'The assistant retrieves confidential procedures from another plant or follows poisoned maintenance instructions from an untrusted document.', 'secure': 'The assistant applies tenant filters, signed-source validation, metadata checks, trusted ranking, and retrieval result verification.', 'mitigations': ['Use tenant-aware vector indexes and metadata filters.', 'Validate source trust, document signatures, and freshness.', 'Detect embedding poisoning and suspicious similarity matches.', 'Cite sources and separate retrieved content from instructions.'], 'asset': 'manufacturing plant maintenance RAG assistant', 'unsafe_action': 'retrieve cross-plant confidential procedures or poisoned maintenance steps', 'safe_action': 'use tenant filters, trusted source ranking, and retrieval validation'}, {'id': 'LLM09', 'title': 'LLM09:2025 Misinformation', 'domain': 'Automotive', 'what': 'Misinformation occurs when an LLM generates false, unsupported, overconfident, or misleading information that users may rely on.', 'scenario': 'An automotive diagnostics assistant explains vehicle fault codes and recommends service actions for technicians and customers.', 'vulnerable': 'The assistant invents service bulletins, gives unsupported safety guidance, or overstates confidence in a diagnosis.', 'secure': 'The assistant cites verified manuals, communicates uncertainty, avoids unsupported claims, and recommends certified inspection for safety-impacting issues.', 'mitigations': ['Require citations from trusted manuals and verified sources.', 'Show uncertainty when evidence is incomplete.', 'Block unsupported safety-critical recommendations.', 'Use expert review for high-impact diagnostic guidance.'], 'asset': 'automotive diagnostics assistant', 'unsafe_action': 'invent service bulletins or provide unsupported safety diagnostics', 'safe_action': 'cite verified manuals, show uncertainty, and recommend certified inspection'}, {'id': 'LLM10', 'title': 'LLM10:2025 Unbounded Consumption', 'domain': 'Aerospace', 'what': 'Unbounded Consumption occurs when an AI system can be abused to consume excessive tokens, compute, tool calls, simulations, storage, or cost.', 'scenario': 'An aerospace engineering assistant helps run analysis summaries and simulation planning tasks.', 'vulnerable': 'The assistant enters recursive analysis, launches excessive simulation requests, or consumes large compute and token budgets.', 'secure': 'The assistant enforces quotas, token budgets, recursion limits, rate limits, job approvals, and cost monitoring.', 'mitigations': ['Set token, cost, tool-call, recursion, and job-execution limits.', 'Rate-limit users, sessions, and expensive workflows.', 'Require approval for high-cost simulations or batch jobs.', 'Monitor denial-of-wallet and resource abuse patterns.'], 'asset': 'aerospace engineering simulation assistant', 'unsafe_action': 'run recursive simulations or excessive tool calls causing compute exhaustion', 'safe_action': 'enforce budgets, quotas, recursion limits, and approval for expensive runs'}]
