def normalize(text):
    return re.sub(r"\s+", " ", (text or "").lower()).strip()

def evaluate_answer(user_answer, expected_keywords):
    answer = normalize(user_answer)
    equivalents = {
        "refuse": ["deny", "decline", "block", "reject", "do not comply"],
        "safe alternative": ["safe option", "allowed alternative", "approved workflow", "safe response"],
        "policy boundary": ["guardrail", "policy", "rule", "boundary", "control"],
        "treat as data": ["untrusted data", "external content", "not instructions", "data not command"],
        "sanitize": ["clean", "redact", "mask", "filter", "neutralize"],
        "isolate": ["separate", "segment", "quarantine", "sandbox"],
        "least privilege": ["minimum access", "limited permission", "scoped access", "need to know"],
        "validate": ["verify", "check", "schema", "confirm", "authenticate"],
        "approval": ["authorize", "review", "sign-off", "human approval"],
        "deny": ["refuse", "decline", "block", "reject"],
        "human review": ["manual review", "escalate", "human in the loop", "reviewer"],
        "audit": ["log", "record", "evidence", "monitor", "trace"]
    }
    hits = []
    for keyword in expected_keywords:
        if keyword in answer:
            hits.append(keyword)
        elif any(term in answer for term in equivalents.get(keyword, [])):
            hits.append(keyword)
    return len(set(hits)) >= 2, sorted(set(hits))

